import{_ as t,o as a,c as o,a3 as d}from"./chunks/framework.BveOjhN0.js";const u=JSON.parse('{"title":"Shared Layout — Developer Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Shared Layout — Developer Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/developer-guide/shared-layout"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Shared Layout — Developer Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/developer-guide/shared-layout"}]]},"headers":[],"relativePath":"developer-guide/shared-layout.md","filePath":"developer-guide/shared-layout.md","lastUpdated":1784157157000}'),n={name:"developer-guide/shared-layout.md"};function r(s,e,i,l,c,p){return a(),o("div",null,[...e[0]||(e[0]=[d(`<h1 id="shared-layout-—-developer-guide" tabindex="-1">Shared Layout — Developer Guide <a class="header-anchor" href="#shared-layout-—-developer-guide" aria-label="Permalink to &quot;Shared Layout — Developer Guide&quot;">​</a></h1><p>App: <code>SaaS-Frontend</code> (React 19 + Vite).</p><h2 id="shared-layout-architecture" tabindex="-1">Shared layout architecture <a class="header-anchor" href="#shared-layout-architecture" aria-label="Permalink to &quot;Shared layout architecture&quot;">​</a></h2><p>Both applications render authenticated pages through the same <code>AppLayout</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AppLayout</span></span>
<span class="line"><span>├── Sidebar          (context-aware nav + brand subtitle)</span></span>
<span class="line"><span>├── Topbar</span></span>
<span class="line"><span>│   ├── Collapse / mobile menu</span></span>
<span class="line"><span>│   ├── Breadcrumbs</span></span>
<span class="line"><span>│   ├── Command palette trigger (⌘K)</span></span>
<span class="line"><span>│   ├── Theme toggle</span></span>
<span class="line"><span>│   ├── Notifications (placeholder)</span></span>
<span class="line"><span>│   ├── Settings shortcut</span></span>
<span class="line"><span>│   └── User menu</span></span>
<span class="line"><span>├── &lt;Outlet /&gt;       (page content in shared max-width container)</span></span>
<span class="line"><span>└── CommandPalette</span></span></code></pre></div><p>Context is <strong>path-based</strong>:</p><table tabindex="0"><thead><tr><th>Application</th><th>Path prefix</th><th>Nav config</th></tr></thead><tbody><tr><td>Tenant</td><td><code>/</code> (e.g. <code>/dashboard</code>)</td><td><code>tenantNavigationGroups</code></td></tr><tr><td>Central</td><td><code>/central/*</code></td><td><code>centralNavigationGroups</code></td></tr></tbody></table><p>Helpers in <code>src/config/routes.ts</code>:</p><ul><li><code>getAuthContext(pathname)</code></li><li><code>dashboardPathFor</code> / <code>profilePathFor</code> / <code>settingsPathFor</code> / <code>loginPathFor</code></li></ul><p>Helpers in <code>src/config/navigation.ts</code>:</p><ul><li><code>getNavigationGroups(context)</code></li><li><code>getNavigationItems(context)</code></li><li><code>applicationLabelFor(context)</code> → <code>&quot;Central Application&quot;</code> | <code>&quot;Tenant Application&quot;</code></li></ul><h2 id="layout-inheritance" tabindex="-1">Layout inheritance <a class="header-anchor" href="#layout-inheritance" aria-label="Permalink to &quot;Layout inheritance&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Shared?</th><th>Notes</th></tr></thead><tbody><tr><td><code>layouts/app-layout.tsx</code></td><td>Yes</td><td>Identical shell for both apps</td></tr><tr><td><code>layouts/auth-layout.tsx</code></td><td>Yes</td><td>Guest auth screens</td></tr><tr><td><code>components/layout/*</code></td><td>Yes</td><td>Reads context from pathname; no Central fork</td></tr><tr><td><code>components/ui/*</code></td><td>Yes</td><td>Primitives (button, card, dialog, table, …)</td></tr><tr><td><code>components/common/*</code></td><td>Yes</td><td>PageHeader, EmptyState, LoadingState, ErrorState</td></tr><tr><td><code>components/dashboard/*</code></td><td>Mostly Central widgets</td><td>WelcomeHero / QuickActions / TenantsOverviewTable stay Central-specific</td></tr><tr><td>Page content</td><td>Per app</td><td>Tenant dashboard renders widget registry from <code>GET /dashboard</code>; CRM modules use shared Kanban + design-system pages</td></tr></tbody></table><p>Do <strong>not</strong> duplicate Sidebar/Topbar for Tenant. Parameterize via navigation config + route helpers.</p><h2 id="reusable-components-preferred" tabindex="-1">Reusable components (preferred) <a class="header-anchor" href="#reusable-components-preferred" aria-label="Permalink to &quot;Reusable components (preferred)&quot;">​</a></h2><p><strong>Shell</strong></p><ul><li><code>AppLayout</code>, <code>Sidebar</code>, <code>Topbar</code>, <code>Breadcrumbs</code>, <code>UserMenu</code>, <code>CommandPalette</code>, <code>ThemeToggle</code></li></ul><p><strong>Page chrome</strong></p><ul><li><code>PageHeader</code>, <code>LoadingState</code>, <code>ErrorState</code>, <code>EmptyState</code>, <code>WidgetContainer</code></li></ul><p><strong>Primitives</strong></p><ul><li>Cards, tables, forms, dialogs, sheets, buttons from <code>components/ui</code></li></ul><p><strong>Placeholders</strong></p><ul><li><code>pages/common/placeholder-page.tsx</code> — reserved module/settings screens</li></ul><h2 id="ui-structure-tenant" tabindex="-1">UI structure (Tenant) <a class="header-anchor" href="#ui-structure-tenant" aria-label="Permalink to &quot;UI structure (Tenant)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Route</th><th>Page</th></tr></thead><tbody><tr><td><code>/dashboard</code></td><td>Tenant dashboard (widget registry: pipeline, tasks, activity, notifications, quick actions)</td></tr><tr><td><code>/leads</code></td><td>Leads Kanban/table + detail drawer</td></tr><tr><td><code>/tasks</code></td><td>Tasks board/list + detail drawer</td></tr><tr><td><code>/settings</code></td><td>Workspace Settings (General / Branding / Mail)</td></tr><tr><td><code>/profile</code></td><td>Shared <code>ProfilePage</code> (API context from pathname)</td></tr></tbody></table><p>Central remains under <code>/central/*</code> with the same shell and its own navigation groups.</p><h2 id="adding-a-tenant-module-to-the-sidebar" tabindex="-1">Adding a Tenant module to the sidebar <a class="header-anchor" href="#adding-a-tenant-module-to-the-sidebar" aria-label="Permalink to &quot;Adding a Tenant module to the sidebar&quot;">​</a></h2><ol><li>Add the path to <code>tenantRoutes</code> in <code>src/config/routes.ts</code>.</li><li>Add a <code>NavigationItem</code> under <code>tenantNavigationGroups</code> with <code>permission</code> <strong>and</strong> <code>module</code> slug.</li><li>Register the route under <code>TenantProtectedRoute</code> → <code>AppLayout</code> in <code>App.tsx</code>.</li><li>Ship list/form/detail UI mirroring Leads (not a long-lived <code>PlaceholderPage</code>).</li></ol><p>Nav visibility is filtered by installed module subscriptions and Spatie permissions.</p><h2 id="auth-api-notes" tabindex="-1">Auth / API notes <a class="header-anchor" href="#auth-api-notes" aria-label="Permalink to &quot;Auth / API notes&quot;">​</a></h2><ul><li>Profile update/password change omit forced <code>apiContext</code> so the axios interceptor uses <code>getAuthContext()</code> from the URL.</li><li>Tenant API base: <code>/api/tenant/v1</code> + <code>X-Tenant-Domain</code>.</li><li>Central API base: <code>/api/central/v1</code>.</li><li>Notifications: poll unread count (~25s); Reverb/Echo deferred.</li></ul><h2 id="explicit-non-goals-shell" tabindex="-1">Explicit non-goals (shell) <a class="header-anchor" href="#explicit-non-goals-shell" aria-label="Permalink to &quot;Explicit non-goals (shell)&quot;">​</a></h2><ul><li>Divergent Central vs Tenant shell redesigns</li><li>Calendar dashboard widget before Calendar module</li><li>Per-module notification stacks outside Laravel notifications + <code>/notifications*</code> APIs</li></ul>`,33)])])}const g=t(n,[["render",r]]);export{u as __pageData,g as default};
